"use strict";(globalThis.webpackChunkhibiscus_docs=globalThis.webpackChunkhibiscus_docs||[]).push([[567],{5226(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docsSidebar":[{"type":"link","href":"/intro","label":"Introduction","docId":"intro","unlisted":false},{"type":"link","href":"/quick-start","label":"Quick Start Guide","docId":"quick-start","unlisted":false},{"type":"link","href":"/getting-started","label":"Getting Started","docId":"getting-started","unlisted":false},{"type":"category","label":"Modules","collapsed":false,"items":[{"type":"link","href":"/dashboard","label":"Dashboard","docId":"dashboard","unlisted":false},{"type":"link","href":"/employees","label":"Employees","docId":"employees","unlisted":false},{"type":"link","href":"/payroll","label":"Payroll","docId":"payroll","unlisted":false},{"type":"link","href":"/leave-management","label":"Leave Management","docId":"leave-management","unlisted":false},{"type":"link","href":"/time-attendance","label":"Time  Attendance","docId":"time-attendance","unlisted":false},{"type":"link","href":"/onboarding-offboarding","label":"Onboarding  Offboarding","docId":"onboarding-offboarding","unlisted":false},{"type":"link","href":"/compliance","label":"Compliance","docId":"compliance","unlisted":false},{"type":"link","href":"/performance","label":"Performance","docId":"performance","unlisted":false},{"type":"link","href":"/benefits","label":"Benefits","docId":"benefits","unlisted":false},{"type":"link","href":"/reports","label":"Reports","docId":"reports","unlisted":false}],"collapsible":true},{"type":"link","href":"/settings","label":"Settings","docId":"settings","unlisted":false},{"type":"link","href":"/faq","label":"FAQ","docId":"faq","unlisted":false}]},"docs":{"benefits":{"id":"benefits","title":"Benefits","description":"The Benefits module administers your employee benefits program with fully configurable plans across 10 plan types. Create your own benefit plans, set employer/employee cost splits, manage eligibility rules, invite your benefits broker, and export EDI 834 files for carrier uploads.","sidebar":"docsSidebar"},"compliance":{"id":"compliance","title":"Compliance","description":"The Compliance module is your audit-readiness hub. It tracks employment document expiry dates, monitors ESA obligations, maintains a CRA filing calendar, and gives you a live compliance score across your organization. If something needs attention \u2014 an expiring certificate, a missed ROE, an overtime violation \u2014 it surfaces here.","sidebar":"docsSidebar"},"dashboard":{"id":"dashboard","title":"Dashboard","description":"The Dashboard is the first thing you see after logging in. It gives you an at-a-glance picture of your entire workforce \u2014 key metrics, recent activity, upcoming starts, and regulatory deadlines \u2014 without needing to navigate into any specific module.","sidebar":"docsSidebar"},"employees":{"id":"employees","title":"Employees","description":"The Employees module is the foundation of Hibiscus HR. Every other module \u2014 payroll, leave, benefits, performance \u2014 pulls from the employee records you maintain here. This module covers the full employee lifecycle: hiring, ongoing management, and termination.","sidebar":"docsSidebar"},"faq":{"id":"faq","title":"Frequently Asked Questions","description":"---","sidebar":"docsSidebar"},"getting-started":{"id":"getting-started","title":"Getting Started","description":"This page covers everything you need to go from zero to running \u2014 logging in, navigating the platform, understanding your role, and orienting yourself on the dashboard.","sidebar":"docsSidebar"},"intro":{"id":"intro","title":"Hibiscus HR \u2014 User Guide","description":"Welcome to the official documentation for Hibiscus HR, the HR platform built from the ground up for Canadian small and medium businesses.","sidebar":"docsSidebar"},"leave-management":{"id":"leave-management","title":"Leave Management","description":"The Leave Management module tracks all employee time-off requests \u2014 vacation, sick days, parental leave, bereavement, and more. All leave policies are built around ESA (Employment Standards Act) minimums for each province, so you are always in compliance regardless of where your employees are based.","sidebar":"docsSidebar"},"onboarding-offboarding":{"id":"onboarding-offboarding","title":"Onboarding & Offboarding","description":"The Onboarding & Offboarding module manages the beginning and end of every employee\'s journey at your organization. Onboarding gives new hires a structured first experience. Offboarding ensures every legal and administrative step is completed \u2014 including filing the Record of Employment (ROE) within the required CRA timeline.","sidebar":"docsSidebar"},"payroll":{"id":"payroll","title":"Payroll","description":"The Payroll module handles your entire Canadian payroll cycle \u2014 from calculating CPP/CPP2 contributions and EI premiums to processing pay runs, generating T4 XML files, and tracking CRA remittance obligations. All calculations use CRA-compliant 2026 tax rates for all 13 provinces and territories, loaded from a centralized rate configuration. Provincial tax is calculated using real tax brackets \u2014 not estimates.","sidebar":"docsSidebar"},"performance":{"id":"performance","title":"Performance","description":"The Performance module manages employee review cycles and goal tracking. You can run quarterly or annual reviews, assign ratings, and track progress on individual goals \u2014 all in one place.","sidebar":"docsSidebar"},"quick-start":{"id":"quick-start","title":"Quick Start Guide","description":"Get your Hibiscus HR account set up and running in under 15 minutes. This guide walks you through the essential first steps \u2014 from your first login to running your first payroll.","sidebar":"docsSidebar"},"reports":{"id":"reports","title":"Reports","description":"The Reports module brings together data from every module in a single analytics hub. Whether you need a workforce headcount for a board presentation, a payroll deduction breakdown for your accountant, or an overtime summary for a compliance review, it is all here.","sidebar":"docsSidebar"},"settings":{"id":"settings","title":"Settings","description":"The Settings module is where you configure your Hibiscus HR account \u2014 your company profile, users and roles, payroll preferences, benefits administration, billing and subscription management, notification rules, security settings, and integrations.","sidebar":"docsSidebar"},"time-attendance":{"id":"time-attendance","title":"Time & Attendance","description":"The Time & Attendance module tracks weekly employee hours, calculates overtime against provincial ESA thresholds, and manages timesheet approvals. Every province has its own overtime threshold \u2014 Hibiscus HR applies the correct rules automatically based on each employee\'s province.","sidebar":"docsSidebar"}}}}')}}]);